     1→/**
     2→ * MMS Infinite Canvas
     3→ *
     4→ * The main canvas component that renders PM schedule data at different zoom levels.
     5→ * Uses deck.gl for strategic view (WebGL) and Konva for tactical/operational views (Canvas 2D).
     6→ *
     7→ * Zoom Level Rendering:
     8→ * - STRATEGIC (0-4): deck.gl WebGL heatmap
     9→ * - TACTICAL_WIDE (4-8): deck.gl WebGL compressed blocks
    10→ * - TACTICAL (8-12): Konva HTML5 Canvas Gantt
    11→ * - OPERATIONAL (12-16): Konva HTML5 Canvas detailed cards
    12→ * - DETAIL (16+): React DOM overlay
    13→ *
    14→ * Based on specs/006-user-interface.md Section 6.3.
    15→ */
    16→
    17→import { useRef } from 'react';
    18→import { Card, NonIdealState, Spinner, Tag, Button, ButtonGroup, OverlayToaster, Intent, Position } from '@blueprintjs/core';
    19→
    20→import { useCanvas, useCanvasData, useFleet, usePm, useUi, useOverlay, loadStrategicData, loadTacticalData, loadTacticalWideData, loadOperationalData, loadDetailData, loadBaselineShadowData } from '../../store';
    21→import type { CanvasSliceState } from '../../store/slices/canvas';
    22→import type { CanvasDataState } from '../../store/slices/canvas';
    23→import type { FleetSliceState } from '../../store/slices/fleet';
    24→import type { PmSliceState } from '../../store/slices/pm';
    25→import type { UiSliceState } from '../../store/slices/ui';
    26→import type { OverlaySliceState } from '../../store/slices/overlay';
    27→import type { ZoomLevel } from '../../store/types';
    28→import { StrategicHeatmapLayer, TacticalWideLayer, TacticalGanttLayer, OperationalDetailLayer, DetailCardOverlay, type HeatmapCell, type PmBlock, type OperationalPmBlock, type DragValidationState, type PmMoveImpact } from './layers';
    29→import { DragConfirmationDialog } from './DragConfirmationDialog';
    30→import {
    31→  quickValidatePmMove,
    32→  createDebouncedValidation,
    33→  getPmMoveImpact,
    34→  commitPmMove,
    35→  createCanvasKeyboardHandler,
    36→  type KeyboardHandlerCallbacks,
    37→  // Accessibility utilities
    38→  initializeAnnouncer,
    39→  announceZoomChange,
    40→  announcePmDeselection,
    41→  prefersReducedMotion,
    42→  onReducedMotionChange,
    43→  FOCUS_RING_STYLES,
    44→} from './utils';
    45→import { KeyboardShortcutsDialog } from '../KeyboardShortcutsDialog';
    46→
    47→// Toaster helper for showing notifications
    48→// Uses the static show method which handles async creation
    49→async function showToast(options: {
    50→  intent: typeof Intent[keyof typeof Intent];
    51→  icon: 'error' | 'tick' | 'warning-sign' | 'info-sign';
    52→  message: string;
    53→  timeout: number;
    54→}): Promise<void> {
    55→  const toaster = await OverlayToaster.createAsync({ position: Position.TOP_RIGHT });
    56→  toaster.show(options);
    57→}
    58→
    59→/** Default canvas dimensions when container size is not available */
    60→const DEFAULT_CANVAS_WIDTH = 1200;
    61→const DEFAULT_CANVAS_HEIGHT = 800;
    62→
    63→// Drag confirmation state interface
    64→interface DragConfirmState {
    65→  isOpen: boolean;
    66→  pmId: string | null;
    67→  pmCode: string;
    68→  trainNumber: string;
    69→  sourceDate: string;
    70→  targetDate: string;
    71→  impact: PmMoveImpact | null;
    72→  isLoadingImpact: boolean;
    73→}
    74→
    75→const initialDragConfirmState: DragConfirmState = {
    76→  isOpen: false,
    77→  pmId: null,
    78→  pmCode: '',
    79→  trainNumber: '',
    80→  sourceDate: '',
    81→  targetDate: '',
    82→  impact: null,
    83→  isLoadingImpact: false,
    84→};
    85→
    86→export function InfiniteCanvas() {
    87→  const { state: canvasStateRaw, actions: canvasActions } = useCanvas();
    88→  const { state: canvasDataStateRaw, actions: canvasDataActions } = useCanvasData();
    89→  const { state: fleetStateRaw } = useFleet();
    90→  const { state: pmStateRaw, actions: pmActions } = usePm();
    91→  const { state: uiStateRaw, actions: uiActions } = useUi();
    92→  const { state: overlayStateRaw, actions: overlayActions } = useOverlay();
    93→
    94→  const canvasState = canvasStateRaw as unknown as CanvasSliceState;
    95→  const canvasDataState = canvasDataStateRaw as unknown as CanvasDataState;
    96→  const fleetState = fleetStateRaw as unknown as FleetSliceState;
    97→  const pmState = pmStateRaw as unknown as PmSliceState;
    98→  const uiState = uiStateRaw as unknown as UiSliceState;
    99→  const overlayState = overlayStateRaw as unknown as OverlaySliceState;
   100→
   101→  const { zoom, zoomLevel, viewport, isPanning, layers } = canvasState;
   102→  const {
   103→    strategicData, strategicLoading, strategicError, fromYear, toYear,
   104→    tacticalWideData, tacticalWideLoading, tacticalWideError, tacticalWideFromDate, tacticalWideToDate,
   105→    tacticalData, tacticalLoading, tacticalError, tacticalFromDate, tacticalToDate,
   106→    operationalData, operationalLoading, operationalError, operationalFromDate, operationalToDate,
   107→    detailData, detailLoading, detailError, detailFromDate, detailToDate, detailExpandedPmIds
   108→  } = canvasDataState;
   109→  const isLoading = fleetState.trains.length === 0;
   110→
   111→  const tooltipPosRef = useRef<{ x: number; y: number }>({ x: 0, y: 0 });
   112→  const tooltipRef = useRef<HTMLDivElement>(null);
   113→
   114→  // Drag state refs
   115→  const dragValidationRef = useRef<DragValidationState | null>(null);
   116→  const draggingPmRef = useRef<{
   117→    pmId: string;
   118→    pmCode: string;
   119→    trainId: string;
   120→    trainNumber: string;
   121→    sourceDate: string;
   122→    constraintStart: string;
   123→    constraintEnd: string;
   124→    isLocked: boolean;
   125→  } | null>(null);
   126→  const dragConfirmRef = useRef<DragConfirmState>(initialDragConfirmState);
   127→
   128→  // Create debounced API validation
   129→  const debouncedValidationRef = useRef(
   130→    createDebouncedValidation((result) => {
   131→      dragValidationRef.current = result;
   132→      if (draggingPmRef.current) {
   133→        pmActions.setDragValidation({
   134→          isValid: result.isValid,
   135→          message: result.message,
   136→          violations: result.violations,
   137→        });
   138→      }
   139→    }, { delay: 150 })
   140→  );
   141→
   142→  // Ref for container to handle focus
   143→  const containerRef = useRef<HTMLDivElement>(null);
   144→
   145→  // Accessibility refs
   146→  const isKeyboardNavigationRef = useRef(false);
   147→  const announcerInitializedRef = useRef(false);
   148→  const reducedMotionCleanupRef = useRef<(() => void) | null>(null);
   149→
   150→  // Initialize announcer and reduced motion detection (runs once)
   151→  if (!announcerInitializedRef.current && typeof window !== 'undefined') {
   152→    announcerInitializedRef.current = true;
   153→    initializeAnnouncer();
   154→
   155→    // Sync reduced motion preference from OS
   156→    const reducedMotion = prefersReducedMotion();
   157→    if (reducedMotion !== uiState.accessibility.reducedMotion) {
   158→      uiActions.setReducedMotion(reducedMotion);
   159→    }
   160→
   161→    // Listen for changes to reduced motion preference
   162→    reducedMotionCleanupRef.current = onReducedMotionChange((prefers) => {
   163→      uiActions.setReducedMotion(prefers);
   164→    });
   165→  }
   166→
   167→  // Get accessibility state
   168→  const { reducedMotion, focusVisible } = uiState.accessibility;
   169→
   170→  // ==========================================================================
   171→  // Keyboard Handler Callbacks
   172→  // ==========================================================================
   173→
   174→  const keyboardCallbacksRef = useRef<KeyboardHandlerCallbacks>({
   175→    // Navigation
   176→    onPan: (direction, amount) => {
   177→      const delta = { dx: 0, dy: 0 };
   178→      switch (direction) {
   179→        case 'up':
   180→          delta.dy = -amount;
   181→          break;
   182→        case 'down':
   183→          delta.dy = amount;
   184→          break;
   185→        case 'left':
   186→          delta.dx = -amount;
   187→          break;
   188→        case 'right':
   189→          delta.dx = amount;
   190→          break;
   191→      }
   192→      canvasActions.pan(delta);
   193→    },
   194→    onGoToToday: () => {
   195→      canvasActions.goToToday();
   196→    },
   197→
   198→    // Zoom
   199→    onZoomIn: () => {
   200→      canvasActions.zoomIn(1.2);
   201→      // Announce zoom change for screen readers
   202→      announceZoomChange(canvasState.zoomLevel, (canvasState.zoom / 20) * 100);
   203→    },
   204→    onZoomOut: () => {
   205→      canvasActions.zoomOut(1.2);
   206→      // Announce zoom change for screen readers
   207→      announceZoomChange(canvasState.zoomLevel, (canvasState.zoom / 20) * 100);
   208→    },
   209→    onSetZoomLevel: (level: ZoomLevel) => {
   210→      canvasActions.setZoomLevel(level);
   211→      // Announce zoom level change for screen readers
   212→      announceZoomChange(level.replace('_', ' '));
   213→      // Mark as keyboard navigation
   214→      isKeyboardNavigationRef.current = true;
   215→      uiActions.setFocusVisible(true);
   216→    },
   217→
   218→    // Selection
   219→    onClearSelection: () => {
   220→      canvasActions.clearSelection();
   221→      // Announce deselection for screen readers
   222→      announcePmDeselection();
   223→    },
   224→    onToggleSelection: () => {
   225→      // Toggle multi-select mode
   226→      canvasActions.setMultiSelect(!canvasState.selection.isMultiSelect);
   227→    },
   228→    onActivateSelected: () => {
   229→      // Activate selected PM - for now, zoom to tactical view showing the PM
   230→      const selectedPmId = canvasState.selection.selectedPmIds[0];
   231→      if (selectedPmId) {
   232→        // Zoom to tactical view to see PM details
   233→        canvasActions.setZoomLevel('TACTICAL');
   234→      }
   235→    },
   236→
   237→    // Editing
   238→    onToggleLock: () => {
   239→      const selectedPmId = canvasState.selection.selectedPmIds[0];
   240→      if (selectedPmId) {
   241→        // In production, this would call the API to lock/unlock
   242→        void showToast({
   243→          intent: Intent.PRIMARY,
   244→          icon: 'info-sign',
   245→          message: 'Lock/unlock PM feature - API integration pending',
   246→          timeout: 3000,
   247→        });
   248→      }
   249→    },
   250→    onDeleteSelected: () => {
   251→      const selectedPmId = canvasState.selection.selectedPmIds[0];
   252→      if (selectedPmId) {
   253→        // In production, this would open a confirmation dialog
   254→        uiActions.openModal({ type: 'confirm-delete-pm', data: { pmId: selectedPmId } });
   255→      }
   256→    },
   257→
   258→    // Dialogs
   259→    onShowKeyboardHelp: () => {
   260→      uiActions.showKeyboardShortcutsDialog();
   261→    },
   262→    onCloseDialog: () => {
   263→      // Close any open dialog
   264→      if (uiState.keyboardShortcutsDialogOpen) {
   265→        uiActions.hideKeyboardShortcutsDialog();
   266→      } else if (uiState.modal.isOpen) {
   267→        uiActions.closeModal();
   268→      }
   269→    },
   270→
   271→    // State queries
   272→    isShortcutsEnabled: () => uiState.shortcutsEnabled,
   273→    hasOpenDialog: () => uiState.modal.isOpen || uiState.keyboardShortcutsDialogOpen || dragConfirmRef.current.isOpen,
   274→    isDragging: () => pmState.drag.isDragging,
   275→    getSelectedPmId: () => canvasState.selection.selectedPmIds[0] || null,
   276→  });
   277→
   278→  // Update ref values on each render (refs don't cause re-renders)
   279→  keyboardCallbacksRef.current.isShortcutsEnabled = () => uiState.shortcutsEnabled;
   280→  keyboardCallbacksRef.current.hasOpenDialog = () => uiState.modal.isOpen || uiState.keyboardShortcutsDialogOpen || dragConfirmRef.current.isOpen;
   281→  keyboardCallbacksRef.current.isDragging = () => pmState.drag.isDragging;
   282→  keyboardCallbacksRef.current.getSelectedPmId = () => canvasState.selection.selectedPmIds[0] || null;
   283→
   284→  // Create keyboard handler
   285→  const handleKeyDown = createCanvasKeyboardHandler(keyboardCallbacksRef.current);
   286→
   287→  const handleWheel = (event: React.WheelEvent) => {
   288→    event.preventDefault();
   289→    const delta = event.deltaY > 0 ? -0.5 : 0.5;
   290→    const newZoom = Math.max(0, Math.min(20, zoom + delta));
   291→    canvasActions.setZoom(newZoom);
   292→  };
   293→
   294→  const handleMouseDown = (event: React.MouseEvent) => {
   295→    if (event.button === 0) {
   296→      canvasActions.startPanning();
   297→    }
   298→  };
   299→
   300→  const handleMouseUp = () => {
   301→    canvasActions.stopPanning();
   302→  };
   303→
   304→  const handleMouseMove = (event: React.MouseEvent) => {
   305→    if (isPanning) {
   306→      canvasActions.pan({
   307→        dx: -event.movementX,
   308→        dy: -event.movementY,
   309→      });
   310→    }
   311→    tooltipPosRef.current = { x: event.clientX, y: event.clientY };
   312→  };
   313→
   314→  const handleLoadStrategicData = () => {
   315→    loadStrategicData(canvasDataActions, {
   316→      fromYear,
   317→      toYear,
   318→    });
   319→  };
   320→
   321→  const handleLoadTacticalWideData = () => {
   322→    loadTacticalWideData(canvasDataActions, {
   323→      fromDate: tacticalWideFromDate,
   324→      toDate: tacticalWideToDate,
   325→    });
   326→  };
   327→
   328→  const handleLoadTacticalData = () => {
   329→    loadTacticalData(canvasDataActions, {
   330→      fromWeek: tacticalFromDate,
   331→      toWeek: tacticalToDate,
   332→    });
   333→  };
   334→
   335→  const handleLoadOperationalData = () => {
   336→    loadOperationalData(canvasDataActions, {
   337→      fromDate: operationalFromDate,
   338→      toDate: operationalToDate,
   339→    });
   340→  };
   341→
   342→  const handleLoadDetailData = () => {
   343→    loadDetailData(canvasDataActions, {
   344→      fromDate: detailFromDate,
   345→      toDate: detailToDate,
   346→    });
   347→  };
   348→
   349→  const handleLoadBaselineShadowData = () => {
   350→    loadBaselineShadowData(overlayActions, {
   351→      fromDate: tacticalFromDate,
   352→      toDate: tacticalToDate,
   353→      baselineId: overlayState.baselineShadowBaselineId ?? undefined,
   354→    });
   355→  };
   356→
   357→  const handleDetailPmSelect = (pmId: string) => {
   358→    canvasActions.selectPm(pmId);
   359→  };
   360→
   361→  const handleDetailPmExpand = (pmId: string) => {
   362→    canvasDataActions.expandDetailPm(pmId);
   363→  };
   364→
   365→  const handleDetailPmCollapse = (pmId: string) => {
   366→    canvasDataActions.collapseDetailPm(pmId);
   367→  };
   368→
   369→  const handleDetailPmEdit = (pmId: string, field: string) => {
   370→    // In production, this would dispatch an edit action to the PM service
   371→    console.log(`Edit PM ${pmId} field ${field}`);
   372→  };
   373→
   374→  const handleDetailPmLock = (pmId: string) => {
   375→    // In production, this would dispatch a lock action
   376→    console.log(`Lock PM ${pmId}`);
   377→  };
   378→
   379→  const handleDetailPmUnlock = (pmId: string) => {
   380→    // In production, this would dispatch an unlock action
   381→    console.log(`Unlock PM ${pmId}`);
   382→  };
   383→
   384→  const handleDetailViewHistory = (pmId: string) => {
   385→    // In production, this would open a history panel
   386→    console.log(`View history for PM ${pmId}`);
   387→  };
   388→
   389→  // ==========================================================================
   390→  // Drag-and-Drop Handlers
   391→  // ==========================================================================
   392→
   393→  const handlePmDragStart = (pmId: string, sourceDate: string) => {
   394→    // Find PM in tactical data
   395→    const pm = tacticalData?.pmBlocks.find(p => p.pmId === pmId);
   396→    if (!pm) return;
   397→
   398→    // Store drag info
   399→    draggingPmRef.current = {
   400→      pmId,
   401→      pmCode: pm.pmCode,
   402→      trainId: pm.trainId,
   403→      trainNumber: pm.trainNumber,
   404→      sourceDate,
   405→      constraintStart: pm.constraintStart,
   406→      constraintEnd: pm.constraintEnd,
   407→      isLocked: pm.isLocked,
   408→    };
   409→
   410→    // Initialize drag state in PM slice
   411→    pmActions.startDrag({ pmId, sourceDate });
   412→
   413→    // Set initial validation (quick check)
   414→    const quickResult = quickValidatePmMove({
   415→      pmId,
   416→      currentDate: sourceDate,
   417→      targetDate: sourceDate,
   418→      trainId: pm.trainId,
   419→      constraintStart: pm.constraintStart,
   420→      constraintEnd: pm.constraintEnd,
   421→      isLocked: pm.isLocked,
   422→    });
   423→    dragValidationRef.current = quickResult;
   424→    pmActions.setDragValidation({
   425→      isValid: quickResult.isValid,
   426→      message: quickResult.message,
   427→      violations: quickResult.violations,
   428→    });
   429→  };
   430→
   431→  const handlePmDragMove = (pmId: string, targetDate: string) => {
   432→    const dragInfo = draggingPmRef.current;
   433→    if (!dragInfo || dragInfo.pmId !== pmId) return;
   434→
   435→    // Update target date in PM slice
   436→    pmActions.updateDragTarget(targetDate);
   437→
   438→    // Quick client-side validation
   439→    const quickResult = quickValidatePmMove({
   440→      pmId,
   441→      currentDate: dragInfo.sourceDate,
   442→      targetDate,
   443→      trainId: dragInfo.trainId,
   444→      constraintStart: dragInfo.constraintStart,
   445→      constraintEnd: dragInfo.constraintEnd,
   446→      isLocked: dragInfo.isLocked,
   447→    });
   448→    dragValidationRef.current = quickResult;
   449→    pmActions.setDragValidation({
   450→      isValid: quickResult.isValid,
   451→      message: quickResult.message,
   452→      violations: quickResult.violations,
   453→    });
   454→
   455→    // If quick validation passes, trigger debounced API validation
   456→    if (quickResult.isValid && targetDate !== dragInfo.sourceDate) {
   457→      debouncedValidationRef.current.validate({
   458→        pmId,
   459→        currentDate: dragInfo.sourceDate,
   460→        targetDate,
   461→        trainId: dragInfo.trainId,
   462→      });
   463→    }
   464→  };
   465→
   466→  const handlePmDragEnd = async (pmId: string, targetDate: string) => {
   467→    const dragInfo = draggingPmRef.current;
   468→    if (!dragInfo || dragInfo.pmId !== pmId) {
   469→      // Clear drag state
   470→      pmActions.cancelDrag();
   471→      draggingPmRef.current = null;
   472→      return;
   473→    }
   474→
   475→    // Cancel pending validation
   476→    debouncedValidationRef.current.cancel();
   477→
   478→    // If no change, just cancel
   479→    if (targetDate === dragInfo.sourceDate) {
   480→      pmActions.cancelDrag();
   481→      draggingPmRef.current = null;
   482→      return;
   483→    }
   484→
   485→    // Final quick validation
   486→    const finalValidation = quickValidatePmMove({
   487→      pmId,
   488→      currentDate: dragInfo.sourceDate,
   489→      targetDate,
   490→      trainId: dragInfo.trainId,
   491→      constraintStart: dragInfo.constraintStart,
   492→      constraintEnd: dragInfo.constraintEnd,
   493→      isLocked: dragInfo.isLocked,
   494→    });
   495→
   496→    // If invalid, snap back and show toast
   497→    if (!finalValidation.isValid) {
   498→      pmActions.cancelDrag();
   499→      draggingPmRef.current = null;
   500→      void showToast({
   501→        intent: Intent.DANGER,
   502→        icon: 'error',
   503→        message: finalValidation.message || 'Cannot reschedule: constraint violation',
   504→        timeout: 5000,
   505→      });
   506→      return;
   507→    }
   508→
   509→    // Open confirmation dialog
   510→    dragConfirmRef.current = {
   511→      isOpen: true,
   512→      pmId,
   513→      pmCode: dragInfo.pmCode,
   514→      trainNumber: dragInfo.trainNumber,
   515→      sourceDate: dragInfo.sourceDate,
   516→      targetDate,
   517→      impact: null,
   518→      isLoadingImpact: true,
   519→    };
   520→    // Force re-render by ending drag with commit=false (optimistic update)
   521→    pmActions.endDrag(false);
   522→
   523→    // Load impact assessment
   524→    try {
   525→      const impact = await getPmMoveImpact({
   526→        pmId,
   527→        currentDate: dragInfo.sourceDate,
   528→        targetDate,
   529→        trainId: dragInfo.trainId,
   530→      });
   531→      dragConfirmRef.current = {
   532→        ...dragConfirmRef.current,
   533→        impact,
   534→        isLoadingImpact: false,
   535→      };
   536→    } catch {
   537→      dragConfirmRef.current = {
   538→        ...dragConfirmRef.current,
   539→        isLoadingImpact: false,
   540→      };
   541→    }
   542→
   543→    // Keep draggingPmRef for the confirmation dialog
   544→  };
   545→
   546→  const handleDragConfirm = async () => {
   547→    const confirmState = dragConfirmRef.current;
   548→    const dragInfo = draggingPmRef.current;
   549→
   550→    if (!confirmState.pmId || !dragInfo) {
   551→      handleDragCancel();
   552→      return;
   553→    }
   554→
   555→    try {
   556→      // Commit the move to API
   557→      await commitPmMove({
   558→        pmId: confirmState.pmId,
   559→        currentDate: confirmState.sourceDate,
   560→        targetDate: confirmState.targetDate,
   561→        trainId: dragInfo.trainId,
   562→        reason: 'Manual reschedule via canvas drag-and-drop',
   563→      });
   564→
   565→      // Confirm move in PM slice (updates local state)
   566→      pmActions.confirmMove(confirmState.pmId);
   567→
   568→      // Show success toast
   569→      void showToast({
   570→        intent: Intent.SUCCESS,
   571→        icon: 'tick',
   572→        message: `${confirmState.pmCode} rescheduled to ${confirmState.targetDate}`,
   573→        timeout: 3000,
   574→      });
   575→
   576→      // Reload tactical data to reflect changes
   577→      handleLoadTacticalData();
