     1→/**
     2→ * ManHourOverlayPanel
     3→ *
     4→ * Overlay panel showing man-hour workload distribution across depots.
     5→ * Displays weekly utilization with stacked bars and adjustment actions.
     6→ *
     7→ * Features:
     8→ * - Weekly depot workload breakdown (required vs available hours)
     9→ * - Utilization status indicators (overloaded, optimal, underutilized)
    10→ * - Pending adjustments summary
    11→ * - Interactive filtering by depot
    12→ *
    13→ * @see specs/006-user-interface.md Section 6.4.3
    14→ */
    15→
    16→import {
    17→  Button,
    18→  ButtonGroup,
    19→  Card,
    20→  Collapse,
    21→  Callout,
    22→  HTMLSelect,
    23→  Icon,
    24→  Intent,
    25→  Spinner,
    26→  Tag,
    27→  Tooltip,
    28→} from '@blueprintjs/core';
    29→
    30→import { useOverlay, useFleet, loadManhourOverlayData } from '../../store';
    31→import type { OverlaySliceState, ManhourWeekData, DepotManhourData, ManhourStatus } from '../../store/slices/overlay';
    32→import type { FleetSliceState } from '../../store/slices/fleet';
    33→
    34→// =============================================================================
    35→// Constants
    36→// =============================================================================
    37→
    38→const LAYOUT = {
    39→  PANEL_WIDTH: 320,
    40→  HEADER_HEIGHT: 48,
    41→  WEEK_ROW_HEIGHT: 36,
    42→  DEPOT_ROW_HEIGHT: 28,
    43→  BAR_HEIGHT: 16,
    44→  COLLAPSED_HEIGHT: 48,
    45→} as const;
    46→
    47→const STATUS_COLORS: Record<ManhourStatus, string> = {
    48→  OVERLOADED: '#DC2626',
    49→  OPTIMAL: '#16A34A',
    50→  UNDERUTILIZED: '#CA8A04',
    51→};
    52→
    53→const STATUS_INTENTS: Record<ManhourStatus, typeof Intent[keyof typeof Intent]> = {
    54→  OVERLOADED: Intent.DANGER,
    55→  OPTIMAL: Intent.SUCCESS,
    56→  UNDERUTILIZED: Intent.WARNING,
    57→};
    58→
    59→// =============================================================================
    60→// Helper Functions
    61→// =============================================================================
    62→
    63→function formatWeekDate(dateStr: string): string {
    64→  const date = new Date(dateStr);
    65→  const month = date.toLocaleDateString('en-US', { month: 'short' });
    66→  const day = date.getDate();
    67→  return `${month} ${day}`;
    68→}
    69→
    70→function getStatusIcon(status: ManhourStatus): 'warning-sign' | 'tick-circle' | 'info-sign' {
    71→  switch (status) {
    72→    case 'OVERLOADED':
    73→      return 'warning-sign';
    74→    case 'OPTIMAL':
    75→      return 'tick-circle';
    76→    case 'UNDERUTILIZED':
    77→      return 'info-sign';
    78→    default:
    79→      return 'info-sign';
    80→  }
    81→}
    82→
    83→function getWorstStatus(depots: DepotManhourData[]): ManhourStatus {
    84→  if (depots.some(d => d.status === 'OVERLOADED')) return 'OVERLOADED';
    85→  if (depots.some(d => d.status === 'UNDERUTILIZED')) return 'UNDERUTILIZED';
    86→  return 'OPTIMAL';
    87→}
    88→
    89→// =============================================================================
    90→// Sub-Components
    91→// =============================================================================
    92→
    93→interface DepotBarProps {
    94→  depot: DepotManhourData;
    95→}
    96→
    97→function DepotBar({ depot }: DepotBarProps) {
    98→  const { depotCode, requiredHours, availableHours, utilizationPct, status, adjustments } = depot;
    99→  const barWidth = Math.min(utilizationPct, 150);
   100→  const hasAdjustments = adjustments.length > 0;
   101→
   102→  return (
   103→    <div
   104→      style={{
   105→        display: 'flex',
   106→        alignItems: 'center',
   107→        gap: 8,
   108→        padding: '4px 0',
   109→        borderBottom: '1px solid var(--pt-divider-black)',
   110→      }}
   111→    >
   112→      <div style={{ width: 60, fontSize: 11, fontWeight: 500, color: 'var(--pt-text-color)' }}>
   113→        {depotCode}
   114→      </div>
   115→
   116→      <div style={{ flex: 1 }}>
   117→        <Tooltip
   118→          content={
   119→            <div style={{ fontSize: 11 }}>
   120→              <div>Required: {requiredHours.toFixed(0)}h</div>
   121→              <div>Available: {availableHours.toFixed(0)}h</div>
   122→              <div>Utilization: {utilizationPct.toFixed(0)}%</div>
   123→              {hasAdjustments && (
   124→                <div style={{ marginTop: 4, borderTop: '1px solid rgba(255,255,255,0.2)', paddingTop: 4 }}>
   125→                  Pending adjustments: {adjustments.length}
   126→                </div>
   127→              )}
   128→            </div>
   129→          }
   130→          position="top"
   131→        >
   132→          <div style={{ position: 'relative', height: LAYOUT.BAR_HEIGHT, backgroundColor: 'var(--pt-divider-black)', borderRadius: 3 }}>
   133→            <div
   134→              style={{
   135→                position: 'absolute',
   136→                left: 0,
   137→                top: 0,
   138→                height: '100%',
   139→                width: `${barWidth}%`,
   140→                backgroundColor: STATUS_COLORS[status],
   141→                borderRadius: 3,
   142→                transition: 'width 0.2s ease',
   143→              }}
   144→            />
   145→            {utilizationPct > 100 && (
   146→              <div
   147→                style={{
   148→                  position: 'absolute',
   149→                  left: '100%',
   150→                  top: '50%',
   151→                  transform: 'translate(-50%, -50%)',
   152→                  fontSize: 9,
   153→                  fontWeight: 700,
   154→                  color: STATUS_COLORS.OVERLOADED,
   155→                }}
   156→              >
   157→                !
   158→              </div>
   159→            )}
   160→          </div>
   161→        </Tooltip>
   162→      </div>
   163→
   164→      <div style={{ width: 50, textAlign: 'right', fontSize: 10, fontFamily: 'monospace', color: 'var(--pt-text-muted)' }}>
   165→        {utilizationPct.toFixed(0)}%
   166→      </div>
   167→
   168→      {hasAdjustments && (
   169→        <Tag minimal intent={Intent.PRIMARY} style={{ fontSize: 9 }}>
   170→          {adjustments.length}
   171→        </Tag>
   172→      )}
   173→    </div>
   174→  );
   175→}
   176→
   177→interface WeekRowProps {
   178→  week: ManhourWeekData;
   179→  isExpanded: boolean;
   180→  onToggle: () => void;
   181→  depotFilter: string | null;
   182→}
   183→
   184→function WeekRow({ week, isExpanded, onToggle, depotFilter }: WeekRowProps) {
   185→  const filteredDepots = depotFilter
   186→    ? week.depots.filter(d => d.depotId === depotFilter)
   187→    : week.depots;
   188→
   189→  const worstStatus = getWorstStatus(filteredDepots);
   190→  const totalRequired = filteredDepots.reduce((sum, d) => sum + d.requiredHours, 0);
   191→  const totalAvailable = filteredDepots.reduce((sum, d) => sum + d.availableHours, 0);
   192→  const pendingAdjustments = filteredDepots.reduce((sum, d) => sum + d.adjustments.length, 0);
   193→
   194→  return (
   195→    <div style={{ marginBottom: 4 }}>
   196→      <div
   197→        onClick={onToggle}
   198→        style={{
   199→          display: 'flex',
   200→          alignItems: 'center',
   201→          gap: 8,
   202→          padding: '8px 12px',
   203→          backgroundColor: isExpanded ? 'var(--pt-intent-primary-5)' : 'var(--pt-app-background-color)',
   204→          borderRadius: 4,
   205→          cursor: 'pointer',
   206→          transition: 'background-color 0.15s ease',
   207→        }}
   208→      >
   209→        <Icon
   210→          icon={isExpanded ? 'chevron-down' : 'chevron-right'}
   211→          size={12}
   212→          color="var(--pt-text-muted)"
   213→        />
   214→
   215→        <Icon
   216→          icon={getStatusIcon(worstStatus)}
   217→          size={14}
   218→          intent={STATUS_INTENTS[worstStatus]}
   219→        />
   220→
   221→        <div style={{ flex: 1 }}>
   222→          <div style={{ fontSize: 12, fontWeight: 600 }}>
   223→            Week of {formatWeekDate(week.weekStart)}
   224→          </div>
   225→          <div style={{ fontSize: 10, color: 'var(--pt-text-muted)' }}>
   226→            {totalRequired.toFixed(0)}h / {totalAvailable.toFixed(0)}h available
   227→          </div>
   228→        </div>
   229→
   230→        {pendingAdjustments > 0 && (
   231→          <Tag minimal intent={Intent.PRIMARY} round style={{ fontSize: 10 }}>
   232→            {pendingAdjustments} adjustments
   233→          </Tag>
   234→        )}
   235→      </div>
   236→
   237→      <Collapse isOpen={isExpanded}>
   238→        <div style={{ padding: '8px 12px 12px 28px' }}>
   239→          {filteredDepots.map(depot => (
   240→            <DepotBar key={depot.depotId} depot={depot} />
   241→          ))}
   242→        </div>
   243→      </Collapse>
   244→    </div>
   245→  );
   246→}
   247→
   248→// =============================================================================
   249→// Main Component
   250→// =============================================================================
   251→
   252→export interface ManHourOverlayPanelProps {
   253→  onClose?: () => void;
   254→}
   255→
   256→export function ManHourOverlayPanel({ onClose }: ManHourOverlayPanelProps) {
   257→  const { state: overlayStateRaw, actions: overlayActions } = useOverlay();
   258→  const { state: fleetStateRaw } = useFleet();
   259→
   260→  const overlayState = overlayStateRaw as unknown as OverlaySliceState;
   261→  const fleetState = fleetStateRaw as unknown as FleetSliceState;
   262→
   263→  const {
   264→    manhourData,
   265→    manhourLoading,
   266→    manhourError,
   267→    manhourWeeks,
   268→    manhourDepotFilter,
   269→    manhourExpandedWeeks,
   270→    manhourPanelExpanded,
   271→  } = overlayState;
   272→
   273→  const depots = fleetState.depots || [];
   274→
   275→  const handleLoadData = () => {
   276→    loadManhourOverlayData(overlayActions, {
   277→      weeks: manhourWeeks,
   278→      depotId: manhourDepotFilter ?? undefined,
   279→    });
   280→  };
   281→
   282→  const handleWeeksChange = (event: React.ChangeEvent<HTMLSelectElement>) => {
   283→    overlayActions.setManhourWeeks(Number(event.target.value));
   284→  };
   285→
   286→  const handleDepotChange = (event: React.ChangeEvent<HTMLSelectElement>) => {
   287→    const value = event.target.value;
   288→    overlayActions.setManhourDepotFilter(value || null);
   289→  };
   290→
   291→  const handleToggleWeek = (weekStart: string) => {
   292→    overlayActions.toggleManhourWeek(weekStart);
   293→  };
   294→
   295→  // Calculate summary stats
   296→  const totalOverloadedWeeks = manhourData?.weeks.filter(w =>
   297→    w.depots.some(d => d.status === 'OVERLOADED')
   298→  ).length ?? 0;
   299→
   300→  const totalOverloadedHours = manhourData?.weeks.reduce((total, week) => {
   301→    return total + week.depots.reduce((weekTotal, depot) => {
   302→      if (depot.status === 'OVERLOADED') {
   303→        return weekTotal + (depot.requiredHours - depot.availableHours);
   304→      }
   305→      return weekTotal;
   306→    }, 0);
   307→  }, 0) ?? 0;
   308→
   309→  return (
   310→    <Card
   311→      elevation={2}
   312→      style={{
   313→        position: 'absolute',
   314→        top: 60,
   315→        right: 12,
   316→        width: LAYOUT.PANEL_WIDTH,
   317→        maxHeight: manhourPanelExpanded ? 'calc(100vh - 140px)' : LAYOUT.COLLAPSED_HEIGHT,
   318→        overflow: 'hidden',
   319→        transition: 'max-height 0.2s ease',
   320→        zIndex: 20,
   321→      }}
   322→    >
   323→      {/* Header */}
   324→      <div
   325→        style={{
   326→          display: 'flex',
   327→          alignItems: 'center',
   328→          gap: 8,
   329→          padding: '12px 16px',
   330→          borderBottom: manhourPanelExpanded ? '1px solid var(--pt-divider-black)' : 'none',
   331→          cursor: 'pointer',
   332→        }}
   333→        onClick={() => overlayActions.toggleManhourPanel()}
   334→      >
   335→        <Icon icon="chart" size={16} intent={Intent.PRIMARY} />
   336→        <div style={{ flex: 1 }}>
   337→          <div style={{ fontSize: 14, fontWeight: 600 }}>Man-Hour Workload</div>
   338→          {manhourData && !manhourPanelExpanded && (
   339→            <div style={{ fontSize: 10, color: 'var(--pt-text-muted)' }}>
   340→              {totalOverloadedWeeks} overloaded weeks
   341→            </div>
   342→          )}
   343→        </div>
   344→        <Icon
   345→          icon={manhourPanelExpanded ? 'chevron-up' : 'chevron-down'}
   346→          size={14}
   347→          color="var(--pt-text-muted)"
   348→        />
   349→        {onClose && (
   350→          <Button
   351→            minimal
   352→            small
   353→            icon="cross"
   354→            onClick={(e) => {
   355→              e.stopPropagation();
   356→              onClose();
   357→            }}
   358→          />
   359→        )}
   360→      </div>
   361→
   362→      {manhourPanelExpanded && (
   363→        <>
   364→          {/* Controls */}
   365→          <div style={{ padding: '12px 16px', borderBottom: '1px solid var(--pt-divider-black)' }}>
   366→            <div style={{ display: 'flex', gap: 8, marginBottom: 8 }}>
   367→              <HTMLSelect
   368→                value={manhourWeeks}
   369→                onChange={handleWeeksChange}
   370→                style={{ flex: 1 }}
   371→                minimal
   372→              >
   373→                <option value={4}>4 weeks</option>
   374→                <option value={8}>8 weeks</option>
   375→                <option value={12}>12 weeks</option>
   376→                <option value={26}>26 weeks</option>
   377→              </HTMLSelect>
   378→
   379→              <HTMLSelect
   380→                value={manhourDepotFilter || ''}
   381→                onChange={handleDepotChange}
   382→                style={{ flex: 1 }}
   383→                minimal
   384→              >
   385→                <option value="">All depots</option>
   386→                {depots.map(depot => (
   387→                  <option key={depot.id} value={depot.id}>
   388→                    {depot.code}
   389→                  </option>
   390→                ))}
   391→              </HTMLSelect>
   392→            </div>
   393→
   394→            <ButtonGroup fill>
   395→              <Button
   396→                intent={Intent.PRIMARY}
   397→                icon="refresh"
   398→                onClick={handleLoadData}
   399→                loading={manhourLoading}
   400→              >
   401→                {manhourData ? 'Refresh' : 'Load Data'}
   402→              </Button>
   403→            </ButtonGroup>
   404→          </div>
   405→
   406→          {/* Content */}
   407→          <div style={{ padding: '12px 16px', overflow: 'auto', maxHeight: 'calc(100vh - 340px)' }}>
   408→            {manhourLoading && !manhourData && (
   409→              <div style={{ textAlign: 'center', padding: 24 }}>
   410→                <Spinner size={32} />
   411→                <div style={{ marginTop: 8, color: 'var(--pt-text-muted)' }}>
   412→                  Loading workload data...
   413→                </div>
   414→              </div>
   415→            )}
   416→
   417→            {manhourError && (
   418→              <Callout intent={Intent.DANGER} icon="error">
   419→                {manhourError}
   420→              </Callout>
   421→            )}
   422→
   423→            {!manhourLoading && !manhourError && !manhourData && (
   424→              <div style={{ textAlign: 'center', padding: 24, color: 'var(--pt-text-muted)' }}>
   425→                <Icon icon="chart" size={32} style={{ marginBottom: 8, opacity: 0.5 }} />
   426→                <div>Click "Load Data" to view workload</div>
   427→              </div>
   428→            )}
   429→
   430→            {manhourData && (
   431→              <>
   432→                {/* Summary */}
   433→                {totalOverloadedWeeks > 0 && (
   434→                  <Callout intent={Intent.WARNING} icon="warning-sign" style={{ marginBottom: 12 }}>
   435→                    <strong>{totalOverloadedWeeks} week{totalOverloadedWeeks > 1 ? 's' : ''}</strong> with resource constraints
   436→                    <div style={{ fontSize: 11, marginTop: 4 }}>
   437→                      {totalOverloadedHours.toFixed(0)} hours over capacity
   438→                    </div>
   439→                  </Callout>
   440→                )}
   441→
   442→                {/* Weeks */}
   443→                {manhourData.weeks.map(week => (
   444→                  <WeekRow
   445→                    key={week.weekStart}
   446→                    week={week}
   447→                    isExpanded={manhourExpandedWeeks.includes(week.weekStart)}
   448→                    onToggle={() => handleToggleWeek(week.weekStart)}
   449→                    depotFilter={manhourDepotFilter}
   450→                  />
   451→                ))}
   452→
   453→                {manhourData.weeks.length === 0 && (
   454→                  <div style={{ textAlign: 'center', padding: 24, color: 'var(--pt-text-muted)' }}>
   455→                    No projections available for selected period
   456→                  </div>
   457→                )}
   458→              </>
   459→            )}
   460→          </div>
   461→
