   345→  const state = rawState as unknown as OverlaySliceState;
   346→
   347→  // Load data callback
   348→  const loadData = () => {
   349→    loadBowWaveOverlayData(
   350→      {
   351→        setBowWaveLoading: actions.setBowWaveLoading,
   352→        setBowWaveData: actions.setBowWaveData,
   353→        setBowWaveError: actions.setBowWaveError,
   354→      },
   355→      { fleetId, planId }
   356→    );
   357→  };
   358→
   359→  // Auto-load data on initial render if never loaded
   360→  // Check in render is safe because we're using slice state to track load status
   361→  const shouldAutoLoad =
   362→    state.bowWaveLastFetch === null &&
   363→    !state.bowWaveLoading &&
   364→    state.bowWaveData === null;
   365→
   366→  if (shouldAutoLoad) {
   367→    // Defer load to next microtask to avoid state updates during render
   368→    Promise.resolve().then(loadData);
   369→  }
   370→
   371→  const riskDisplay = selectBowWaveRiskDisplay(state);
   372→  const intent = RISK_INTENT_MAP[riskDisplay.level];
   373→  const icon = RISK_ICON_MAP[riskDisplay.level];
   374→
   375→  // Loading state
   376→  if (state.bowWaveLoading && !state.bowWaveData) {
   377→    return (
   378→      <Tag minimal className={className}>
   379→        <Spinner size={12} />
   380→        <span style={{ marginLeft: 6 }}>Loading...</span>
   381→      </Tag>
   382→    );
   383→  }
   384→
   385→  // Compact version for toolbar
   386→  if (compact) {
   387→    return (
   388→      <Popover
   389→        content={<BowWavePopoverContent state={state} onRefresh={loadData} />}
   390→        placement="bottom"
   391→        interactionKind="hover"
   392→        hoverOpenDelay={200}
   393→      >
   394→        <Tooltip content={riskDisplay.label} placement="bottom">
   395→          <Tag
   396→            intent={intent}
   397→            icon={icon}
   398→            interactive
   399→            className={className}
   400→            style={{ cursor: 'pointer' }}
   401→          >
   402→            {state.bowWaveData
   403→              ? `${Math.round(state.bowWaveData.riskScore * 100)}%`
   404→              : 'N/A'}
   405→          </Tag>
   406→        </Tooltip>
   407→      </Popover>
   408→    );
   409→  }
   410→
   411→  // Full version for status bar
   412→  return (
   413→    <Popover
   414→      content={<BowWavePopoverContent state={state} onRefresh={loadData} />}
   415→      placement="top"
   416→      interactionKind="hover"
   417→      hoverOpenDelay={200}
   418→    >
   419→      <Tag
   420→        intent={intent}
   421→        icon={icon}
   422→        interactive
   423→        className={className}
   424→        style={{ cursor: 'pointer' }}
   425→      >
   426→        {riskDisplay.label}
   427→        {state.bowWaveData && (
   428→          <span style={{ marginLeft: 6, opacity: 0.8 }}>
   429→            ({Math.round(state.bowWaveData.riskScore * 100)}%)
   430→          </span>
   431→        )}
   432→      </Tag>
   433→    </Popover>
   434→  );
   435→}
   436→
   437→export default BowWaveIndicator;
   438→

