/**
 * Canvas Keyboard Handler
 *
 * Handles keyboard shortcuts for the MMS infinite canvas.
 * Implements shortcuts from spec 006.9.2 without using React hooks (useState, useEffect).
 *
 * @see specs/006-user-interface.md Section 6.9.2
 */

import type { ZoomLevel } from '../../../store/types';

/**
 * Pan direction for arrow key navigation
 */
type PanDirection = 'up' | 'down' | 'left' | 'right';

/**
 * Keyboard handler callbacks
 */
export interface KeyboardHandlerCallbacks {
  // Navigation
  onPan: (direction: PanDirection, amount: number) => void;
  onGoToToday: () => void;

  // Zoom
  onZoomIn: () => void;
  onZoomOut: () => void;
  onSetZoomLevel: (level: ZoomLevel) => void;

  // Selection
  onClearSelection: () => void;
  onToggleSelection: () => void;
  onActivateSelected: () => void;

  // Editing
  onToggleLock: () => void;
  onDeleteSelected: () => void;

  // Dialogs
  onShowKeyboardHelp: () => void;
  onCloseDialog: () => void;

  // State queries
  isShortcutsEnabled: () => boolean;
  hasOpenDialog: () => boolean;
  isDragging: () => boolean;
  getSelectedPmId: () => string | null;
}

/**
 * Default pan amount in pixels
 */
const DEFAULT_PAN_AMOUNT = 50;

/**
 * Map keyboard number to zoom level
 */
const ZOOM_LEVEL_MAP: Record<string, ZoomLevel> = {
  '1': 'STRATEGIC',
  '2': 'TACTICAL_WIDE',
  '3': 'TACTICAL',
  '4': 'OPERATIONAL',
  '5': 'DETAIL',
};

/**
 * Check if the event target is an input element where shortcuts should be disabled
 */
function isInputElement(event: KeyboardEvent): boolean {
  const target = event.target as HTMLElement;
  const tagName = target.tagName.toLowerCase();

  // Disable shortcuts in input elements
  if (tagName === 'input' || tagName === 'textarea' || tagName === 'select') {
    return true;
  }

  // Disable shortcuts in contenteditable elements
  if (target.isContentEditable) {
    return true;
  }

  // Check for BlueprintJS editable text
  if (target.classList.contains('bp5-editable-text-content')) {
    return true;
  }

  return false;
}

/**
 * Handle keyboard events for the canvas
 *
 * @param event - The keyboard event
 * @param callbacks - Handler callbacks
 * @returns true if the event was handled, false otherwise
 */
export function handleCanvasKeyDown(
  event: KeyboardEvent,
  callbacks: KeyboardHandlerCallbacks
): boolean {
  // Skip if typing in an input
  if (isInputElement(event)) {
    return false;
  }

  // Skip if shortcuts are disabled (except for ?)
  if (!callbacks.isShortcutsEnabled() && event.key !== '?') {
    return false;
  }

  const { key, shiftKey, ctrlKey, metaKey, altKey } = event;

  // Normalize key for cross-platform compatibility
  const normalizedKey = key.toLowerCase();

  // Handle Escape key (always works, even during drag)
  if (key === 'Escape') {
    event.preventDefault();

    if (callbacks.isDragging()) {
      // Cancel drag handled by drag system
      return true;
    }

    if (callbacks.hasOpenDialog()) {
      callbacks.onCloseDialog();
      return true;
    }

    // Clear selection
    callbacks.onClearSelection();
    return true;
  }

  // Don't process other shortcuts during drag or with open dialog
  if (callbacks.isDragging() || callbacks.hasOpenDialog()) {
    return false;
  }

  // Handle ? for keyboard shortcuts help
  if (key === '?' || (shiftKey && key === '/')) {
    event.preventDefault();
    callbacks.onShowKeyboardHelp();
    return true;
  }

  // Handle modifier key combinations first
  // Most canvas shortcuts shouldn't use modifiers
  if (ctrlKey || metaKey || altKey) {
    // Allow Ctrl/Cmd shortcuts to pass through for browser defaults
    return false;
  }

  // Arrow keys - Pan canvas
  if (key === 'ArrowUp' || key === 'ArrowDown' || key === 'ArrowLeft' || key === 'ArrowRight') {
    event.preventDefault();
    const amount = shiftKey ? DEFAULT_PAN_AMOUNT * 3 : DEFAULT_PAN_AMOUNT;

    switch (key) {
      case 'ArrowUp':
        callbacks.onPan('up', amount);
        break;
      case 'ArrowDown':
        callbacks.onPan('down', amount);
        break;
      case 'ArrowLeft':
        callbacks.onPan('left', amount);
        break;
      case 'ArrowRight':
        callbacks.onPan('right', amount);
        break;
    }
    return true;
  }

  // Home key - Go to today
  if (key === 'Home') {
    event.preventDefault();
    callbacks.onGoToToday();
    return true;
  }

  // + key - Zoom in (also = key without shift on most keyboards)
  if (key === '+' || key === '=' || (shiftKey && key === '=')) {
    event.preventDefault();
    callbacks.onZoomIn();
    return true;
  }

  // - key - Zoom out
  if (key === '-') {
    event.preventDefault();
    callbacks.onZoomOut();
    return true;
  }

  // Number keys 1-5 - Switch zoom levels
  if (ZOOM_LEVEL_MAP[key]) {
    event.preventDefault();
    callbacks.onSetZoomLevel(ZOOM_LEVEL_MAP[key]);
    return true;
  }

  // Single letter shortcuts (case insensitive)
  switch (normalizedKey) {
    // t - Go to today
    case 't':
      event.preventDefault();
      callbacks.onGoToToday();
      return true;

    // s - Strategic view
    case 's':
      event.preventDefault();
      callbacks.onSetZoomLevel('STRATEGIC');
      return true;

    // o - Operational view
    case 'o':
      event.preventDefault();
      callbacks.onSetZoomLevel('OPERATIONAL');
      return true;

    // l - Lock/unlock selected PM
    case 'l':
      if (callbacks.getSelectedPmId()) {
        event.preventDefault();
        callbacks.onToggleLock();
        return true;
      }
      break;

    // Space - Toggle selection
    case ' ':
      event.preventDefault();
      callbacks.onToggleSelection();
      return true;
  }

  // Enter - Activate selected element
  if (key === 'Enter') {
    event.preventDefault();
    callbacks.onActivateSelected();
    return true;
  }

  // Delete/Backspace - Delete selected PM (with confirmation)
  if (key === 'Delete' || key === 'Backspace') {
    if (callbacks.getSelectedPmId()) {
      event.preventDefault();
      callbacks.onDeleteSelected();
      return true;
    }
  }

  return false;
}

/**
 * Create a keyboard event handler bound to callbacks
 *
 * @param callbacks - Handler callbacks
 * @returns Event handler function
 */
export function createCanvasKeyboardHandler(
  callbacks: KeyboardHandlerCallbacks
): (event: React.KeyboardEvent) => void {
  return (event: React.KeyboardEvent) => {
    const handled = handleCanvasKeyDown(event.nativeEvent, callbacks);
    if (handled) {
      event.stopPropagation();
    }
  };
}

/**
 * Keyboard Shortcuts Dialog
 *
 * Displays the list of keyboard shortcuts available in the MMS canvas.
 * Triggered by pressing '?' or from the Help menu.
 *
 * @see specs/006-user-interface.md Section 6.9.2
 */

import { Dialog, Classes, HTMLTable, Tag, Intent } from '@blueprintjs/core';
import { useUi } from '../store';
import type { UiSliceState } from '../store/slices/ui';

/**
 * Keyboard shortcut definition
 */
interface ShortcutDefinition {
  key: string;
  description: string;
  category: 'navigation' | 'zoom' | 'selection' | 'editing' | 'general';
}

/**
 * All keyboard shortcuts per spec 006.9.2
 */
const KEYBOARD_SHORTCUTS: ShortcutDefinition[] = [
  // Navigation shortcuts
  { key: 'Arrow keys', description: 'Pan canvas', category: 'navigation' },
  { key: 'Home', description: 'Go to today', category: 'navigation' },
  { key: 't', description: 'Go to today', category: 'navigation' },
  { key: 'Tab', description: 'Navigate between panels', category: 'navigation' },
  { key: 'Shift+Tab', description: 'Navigate between panels (reverse)', category: 'navigation' },

  // Zoom shortcuts
  { key: '+', description: 'Zoom in', category: 'zoom' },
  { key: '-', description: 'Zoom out', category: 'zoom' },
  { key: '1', description: 'Strategic view (12-year)', category: 'zoom' },
  { key: '2', description: 'Tactical-wide view (1-year)', category: 'zoom' },
  { key: '3', description: 'Tactical view (12-week)', category: 'zoom' },
  { key: '4', description: 'Operational view (4-week)', category: 'zoom' },
  { key: '5', description: 'Detail view (1-week)', category: 'zoom' },
  { key: 's', description: 'Strategic view', category: 'zoom' },
  { key: 'o', description: 'Operational view', category: 'zoom' },

  // Selection shortcuts
  { key: 'Enter', description: 'Activate selected element', category: 'selection' },
  { key: 'Space', description: 'Toggle selection', category: 'selection' },
  { key: 'Escape', description: 'Cancel drag / Close dialog / Deselect', category: 'selection' },

  // Editing shortcuts
  { key: 'l', description: 'Lock/unlock selected PM', category: 'editing' },
  { key: 'Delete', description: 'Cancel selected PM (with confirmation)', category: 'editing' },

  // General shortcuts
  { key: '?', description: 'Show keyboard shortcuts (this dialog)', category: 'general' },
];

/**
 * Category labels and order
 */
const CATEGORIES: { id: ShortcutDefinition['category']; label: string }[] = [
  { id: 'navigation', label: 'Navigation' },
  { id: 'zoom', label: 'Zoom & Views' },
  { id: 'selection', label: 'Selection' },
  { id: 'editing', label: 'Editing' },
  { id: 'general', label: 'General' },
];

/**
 * Shortcut key badge component
 */
function KeyBadge({ keyName }: { keyName: string }) {
  const parts = keyName.split('+');
  return (
    <span style={{ display: 'inline-flex', gap: '4px', alignItems: 'center' }}>
      {parts.map((part, index) => (
        <span key={index}>
          <Tag minimal style={{ fontFamily: 'monospace', fontWeight: 600, fontSize: '12px' }}>
            {part.trim()}
          </Tag>
          {index < parts.length - 1 && <span style={{ margin: '0 2px', color: '#5c7080' }}>+</span>}
        </span>
      ))}
    </span>
  );
}

/**
 * Shortcuts table for a category
 */
function ShortcutCategory({
  category,
  shortcuts,
}: {
  category: { id: string; label: string };
  shortcuts: ShortcutDefinition[];
}) {
  return (
    <div style={{ marginBottom: '20px' }}>
      <h4 style={{ margin: '0 0 8px 0', color: '#5c7080', fontSize: '13px', fontWeight: 600 }}>
        {category.label}
      </h4>
      <HTMLTable
        compact
        striped
        style={{ width: '100%', fontSize: '13px' }}
      >
        <tbody>
          {shortcuts.map((shortcut) => (
            <tr key={shortcut.key}>
              <td style={{ width: '140px', paddingRight: '16px' }}>
                <KeyBadge keyName={shortcut.key} />
              </td>
              <td>{shortcut.description}</td>
            </tr>
          ))}
        </tbody>
      </HTMLTable>
    </div>
  );
}

/**
 * Keyboard Shortcuts Dialog Component
 *
 * Displays all available keyboard shortcuts organized by category.
 * Uses @belt/tools state management for dialog visibility.
 */
export function KeyboardShortcutsDialog() {
  const { state: uiStateRaw, actions: uiActions } = useUi();
  const uiState = uiStateRaw as unknown as UiSliceState;

  const handleClose = () => {
    uiActions.hideKeyboardShortcutsDialog();
  };

  // Group shortcuts by category
  const shortcutsByCategory = CATEGORIES.map((category) => ({
    category,
    shortcuts: KEYBOARD_SHORTCUTS.filter((s) => s.category === category.id),
  })).filter(({ shortcuts }) => shortcuts.length > 0);

  return (
    <Dialog
      isOpen={uiState.keyboardShortcutsDialogOpen}
      onClose={handleClose}
      title="Keyboard Shortcuts"
      icon="key-command"
      style={{ width: '520px' }}
    >

