/**
 * Accessibility Announcer Utility
 *
 * Provides screen reader announcements for canvas state changes.
 * Uses ARIA live regions to announce changes to assistive technology users.
 *
 * @see WCAG 2.1 Success Criterion 4.1.3 Status Messages
 * @see specs/006-user-interface.md Section 6.10 (Accessibility)
 */

// =============================================================================
// Types
// =============================================================================

/**
 * Priority level for announcements:
 * - polite: Wait for current announcements to finish (default)
 * - assertive: Interrupt current announcements immediately
 */
export type AnnouncementPriority = 'polite' | 'assertive';

/**
 * Announcement categories for better organization and filtering
 */
export type AnnouncementCategory =
  | 'navigation' // Zoom, pan, view changes
  | 'selection' // PM or train selection changes
  | 'drag' // Drag-and-drop operations
  | 'data' // Data loading states
  | 'validation' // Constraint validation results
  | 'action'; // User action feedback

/**
 * Announcement message configuration
 */
export interface Announcement {
  message: string;
  priority: AnnouncementPriority;
  category: AnnouncementCategory;
  timestamp: number;
}

// =============================================================================
// Announcer Singleton
// =============================================================================

let politeRegion: HTMLElement | null = null;
let assertiveRegion: HTMLElement | null = null;
let announcementHistory: Announcement[] = [];
const MAX_HISTORY = 50;

/**
 * Creates the ARIA live regions if they don't exist.
 * Should be called once when the application starts.
 */
export function initializeAnnouncer(): void {
  if (typeof document === 'undefined') return;

  // Create polite live region
  if (!politeRegion) {
    politeRegion = document.createElement('div');
    politeRegion.setAttribute('id', 'mms-a11y-polite');
    politeRegion.setAttribute('role', 'status');
    politeRegion.setAttribute('aria-live', 'polite');
    politeRegion.setAttribute('aria-atomic', 'true');
    applyHiddenStyles(politeRegion);
    document.body.appendChild(politeRegion);
  }

  // Create assertive live region
  if (!assertiveRegion) {
    assertiveRegion = document.createElement('div');
    assertiveRegion.setAttribute('id', 'mms-a11y-assertive');
    assertiveRegion.setAttribute('role', 'alert');
    assertiveRegion.setAttribute('aria-live', 'assertive');
    assertiveRegion.setAttribute('aria-atomic', 'true');
    applyHiddenStyles(assertiveRegion);
    document.body.appendChild(assertiveRegion);
  }
}

/**
 * Cleans up the ARIA live regions.
 * Should be called when the application unmounts.
 */
export function destroyAnnouncer(): void {
  if (politeRegion?.parentNode) {
    politeRegion.parentNode.removeChild(politeRegion);
    politeRegion = null;
  }
  if (assertiveRegion?.parentNode) {
    assertiveRegion.parentNode.removeChild(assertiveRegion);
    assertiveRegion = null;
  }
  announcementHistory = [];
}

/**
 * Applies visually hidden styles to an element while keeping it accessible
 * to screen readers. Uses the standard "sr-only" technique.
 */
function applyHiddenStyles(element: HTMLElement): void {
  element.style.cssText = `
    position: absolute;
    width: 1px;
    height: 1px;
    padding: 0;
    margin: -1px;
    overflow: hidden;
    clip: rect(0, 0, 0, 0);
    white-space: nowrap;
    border: 0;
  `;
}

// =============================================================================
// Core Announcement Functions
// =============================================================================

/**
 * Announces a message to screen reader users.
 *
 * @param message - The message to announce
 * @param options - Configuration options
 * @returns The announcement object
 */
export function announce(
  message: string,
  options: {
    priority?: AnnouncementPriority;
    category?: AnnouncementCategory;
  } = {}
): Announcement {
  const priority = options.priority ?? 'polite';
  const category = options.category ?? 'action';

  const announcement: Announcement = {
    message,
    priority,
    category,
    timestamp: Date.now(),
  };

  // Add to history
  announcementHistory.push(announcement);
  if (announcementHistory.length > MAX_HISTORY) {
    announcementHistory.shift();
  }

  // Initialize if needed
  if (!politeRegion || !assertiveRegion) {
    initializeAnnouncer();
  }

  // Set the message in the appropriate live region
  const region = priority === 'assertive' ? assertiveRegion : politeRegion;
  if (region) {
    // Clear and set message (forces re-announcement)
    region.textContent = '';
    // Use setTimeout to ensure the clear takes effect
    setTimeout(() => {
      region.textContent = message;
    }, 50);
  }

  return announcement;
}

/**
 * Gets the announcement history (for debugging/testing)
 */
export function getAnnouncementHistory(): readonly Announcement[] {
  return announcementHistory;
}

/**
 * Clears the announcement history
 */
export function clearAnnouncementHistory(): void {
  announcementHistory = [];
}

// =============================================================================
// Convenience Functions for Common Announcements
// =============================================================================

/**
 * Announces a zoom level change
 */
export function announceZoomChange(
  zoomLevel: string,
  zoomPercent?: number
): Announcement {
  const message = zoomPercent
    ? `Zoom level: ${zoomLevel}, ${Math.round(zoomPercent)}%`
    : `Zoom level: ${zoomLevel}`;
  return announce(message, { category: 'navigation', priority: 'polite' });
}

/**
 * Announces a navigation to a specific date
 */
export function announceNavigateToDate(date: string): Announcement {
  return announce(`Navigated to ${date}`, {
    category: 'navigation',
    priority: 'polite',
  });
}

/**
 * Announces PM selection
 */
export function announcePmSelection(
  pmCode: string,
  trainNumber: string,
  date: string
): Announcement {
  return announce(
    `Selected PM ${pmCode} for train ${trainNumber} on ${date}`,
    { category: 'selection', priority: 'polite' }
  );
}

/**
 * Announces PM deselection
 */
export function announcePmDeselection(): Announcement {
  return announce('Selection cleared', {
    category: 'selection',
    priority: 'polite',
  });
}

/**
 * Announces train selection
 */
export function announceTrainSelection(
  trainNumber: string,
  fleetCode?: string
): Announcement {
  const message = fleetCode
    ? `Selected train ${trainNumber} from fleet ${fleetCode}`
    : `Selected train ${trainNumber}`;
  return announce(message, { category: 'selection', priority: 'polite' });
}

/**
 * Announces the start of a drag operation
 */
export function announceDragStart(
  pmCode: string,
  trainNumber: string,
  sourceDate: string
): Announcement {
  return announce(
    `Dragging PM ${pmCode} for train ${trainNumber} from ${sourceDate}. Use arrow keys to move, Enter to drop, Escape to cancel.`,
    { category: 'drag', priority: 'assertive' }
  );
}

/**
 * Announces drag validation result
 */
export function announceDragValidation(
  isValid: boolean,
  targetDate: string,
  violations?: string[]
): Announcement {
  if (isValid) {
    return announce(`Valid drop target: ${targetDate}`, {
      category: 'validation',
      priority: 'polite',
    });
  } else {
    const violationText = violations?.join('. ') ?? 'Invalid position';
    return announce(`Invalid: ${violationText}`, {
      category: 'validation',
      priority: 'assertive',
    });
  }
}

/**
 * Announces drag completion
 */
export function announceDragComplete(
  pmCode: string,
  fromDate: string,
  toDate: string
): Announcement {
  return announce(
    `Moved PM ${pmCode} from ${fromDate} to ${toDate}`,
    { category: 'drag', priority: 'assertive' }
  );
}

/**
 * Announces drag cancellation
 */
export function announceDragCancel(): Announcement {
  return announce('Drag cancelled', {
    category: 'drag',
    priority: 'polite',
  });
}

/**
 * Announces data loading state
 */
export function announceDataLoading(what: string): Announcement {
  return announce(`Loading ${what}...`, {
    category: 'data',
    priority: 'polite',
  });
}

/**
 * Announces data loaded successfully
 */
export function announceDataLoaded(
  what: string,
  count?: number
): Announcement {
  const message = count !== undefined
    ? `Loaded ${count} ${what}`
    : `${what} loaded`;
  return announce(message, { category: 'data', priority: 'polite' });
}

/**
 * Announces an error
 */
export function announceError(errorMessage: string): Announcement {
  return announce(`Error: ${errorMessage}`, {
    category: 'action',
    priority: 'assertive',
  });
}

/**
 * Announces a successful action
 */
export function announceSuccess(message: string): Announcement {
  return announce(message, {
    category: 'action',
    priority: 'polite',
  });
}

/**
 * Announces keyboard shortcut activation
 */
export function announceShortcutActivated(shortcut: string): Announcement {
  return announce(`Keyboard shortcut: ${shortcut}`, {
    category: 'action',
    priority: 'polite',
  });
}

// =============================================================================
// Canvas-Specific Announcements
// =============================================================================

/**
 * Announces the current canvas view summary for screen readers
 */
export function announceCanvasSummary(
  zoomLevel: string,
  visibleTrainCount: number,
  visiblePmCount: number,
  dateRange: { start: string; end: string }
): Announcement {
  return announce(
    `Canvas view: ${zoomLevel}. Showing ${visibleTrainCount} trains, ${visiblePmCount} PMs, from ${dateRange.start} to ${dateRange.end}. Press question mark for keyboard shortcuts.`,
    { category: 'navigation', priority: 'polite' }
  );
}

/**
 * Announces PM block details when focused
 */
export function announcePmBlockFocused(
  pmCode: string,
  trainNumber: string,
  date: string,
  status: string,
  depot: string,
  duration: number
): Announcement {
  return announce(
    `PM ${pmCode}, train ${trainNumber}, ${date}, status: ${status}, depot: ${depot}, duration: ${duration} hours. Press Enter to select, L to lock, Delete to remove.`,
    { category: 'selection', priority: 'polite' }
  );
}

/**
 * Announces constraint wall (compliance window boundary)
 */
export function announceConstraintWall(
  type: 'start' | 'end',
  date: string,
  trainNumber: string
): Announcement {
  const boundary = type === 'start' ? 'Earliest allowed date' : 'Latest allowed date';
  return announce(
    `${boundary} for train ${trainNumber}: ${date}`,
    { category: 'validation', priority: 'polite' }
  );
}

/**
 * Announces overlay toggle
 */
export function announceOverlayToggle(
  overlayName: string,
  enabled: boolean
): Announcement {
  return announce(
    `${overlayName} overlay ${enabled ? 'enabled' : 'disabled'}`,
    { category: 'navigation', priority: 'polite' }
  );
}

